template <typename UnionPtrType> BitratePtr Bitrate::Clone() const
{
    switch (tag_) {
    case Tag::kConstant:
        return NewConstant(mojo::Clone(*data_.constant));
    case Tag::kVariable:
        return NewVariable(mojo::Clone(*data_.variable));
    }
    return nullptr;
}

template <typename T, typename std::enable_if<std::is_same<T, Bitrate>::value>::type*> bool Bitrate::Equals(const T& other) const
{
    if (tag_ != other.which())
        return false;

    switch (tag_) {
    case Tag::kConstant:
        return mojo::Equals(*(data_.constant), *(other.data_.constant));
    case Tag::kVariable:
        return mojo::Equals(*(data_.variable), *(other.data_.variable));
    }

    return false;
}
